import{_ as i,o as p,c as a,af as e}from"./chunks/framework.DuHE0XFB.js";const c=JSON.parse('{"title":"开车需要注意的事情〜","description":"","frontmatter":{"title":"开车需要注意的事情〜","date":"2017-10-19 20:04:50 +0800"},"headers":[],"relativePath":"posts/car.md","filePath":"posts/car.md","lastUpdated":1783570921000}'),t={name:"posts/car.md"};function r(o,l,s,h,n,d){return p(),a("div",null,[...l[0]||(l[0]=[e('<p>总结了一些开车时需要注意的事情，希望能帮助到刚拿到驾照的新司机。</p><h2 id="起步" tabindex="-1">起步 <a class="header-anchor" href="#起步" aria-label="Permalink to &quot;起步&quot;">​</a></h2><ul><li><p>不要酒后/疲劳/生气时开车</p></li><li><p>确认车周围是否有障碍物或人，并系安全带</p></li><li><p>打左转向灯提醒后方来车，并通过后视镜确认安全后再起步</p></li></ul><h2 id="行车" tabindex="-1">行车 <a class="header-anchor" href="#行车" aria-label="Permalink to &quot;行车&quot;">​</a></h2><ul><li><p>频繁看后视镜，就象打王者荣耀时看小地图一样</p></li><li><p>让速不让路，除非前后是能夹死你的大车</p></li><li><p>变道打转向灯，确认安全后变道不要犹豫，并且小心目标车道左边或右边车道的车也要并进来</p></li><li><p>不要跟其他车并排行驶</p></li><li><p>走车道中间，否则会被挤，也不安全</p></li><li><p>转弯让直行，右转让左转，过路口让行人</p></li><li><p>遇到紧急情况先踩刹车，在看后视镜</p></li><li><p>在不确定要踩油门加速的情况下，把脚悬在刹车上</p></li><li><p>油门和刹车要慢踩慢抬，特别是车上有晕车的人时</p></li><li><p>不要开太快，十次出事九次快</p></li><li><p>离路边停的车远点，他们随时可能打开车门，也可能从车前后出来人</p></li><li><p>经过路口有意识地放开油门或者轻踩刹车，以防有路人或车冲出来</p></li><li><p>视线被挡时必须慢，例如右面有公交车时，要小心有人从车前跑出来</p></li></ul><h2 id="跟车" tabindex="-1">跟车 <a class="header-anchor" href="#跟车" aria-label="Permalink to &quot;跟车&quot;">​</a></h2><ul><li><p>保持车距眼光要放远，有车并进来后，及时刹车拉开车距，避免它突然刹车</p></li><li><p>不跟大车，大车档视线、货车掉东西</p></li><li><p>不跟出租车，因为它随时会踩刹车</p></li><li><p>前车刹车你也刹，前车突然变道，最好踩下刹车并同时考虑变道，有可能前方有事故</p></li><li><p>雨雪天气以及车上满员时要提前踩刹车</p></li><li><p>超车前先给信号，闪两下大灯，并且要注意后车是否也要超车</p></li><li><p>堵车时不要跟前车太近，避免想换车道时距离不够</p></li></ul><h2 id="倒车" tabindex="-1">倒车 <a class="header-anchor" href="#倒车" aria-label="Permalink to &quot;倒车&quot;">​</a></h2><ul><li><p>方向盘调整要快，车速要慢</p></li><li><p>如果不是在坡路上不要踩油门，特别是方向盘不正的情况下会很危险</p></li><li><p>别人按喇叭催你时千万别着急，否则出了事担责任的是你自己</p></li></ul><h2 id="高速" tabindex="-1">高速 <a class="header-anchor" href="#高速" aria-label="Permalink to &quot;高速&quot;">​</a></h2><ul><li><p>远离大车</p></li><li><p>不出高速尽量不走外侧车道，出高速下匝道时也要小心旁边车道有车强行并线下匝道，自己也要注意，宁可多走一段路，也不要强行并线下匝道</p></li><li><p>因为速度很快，不要急打方向</p></li><li><p>急刹车的时候看下后视镜，高速上被追尾的死亡率远远大于追尾的</p></li><li><p>冲出动物时，宁可直接撞，也别躲！</p></li><li><p>在高速上发生爆胎或过积水，首先稳住方向盘，千万不要猛打方向或使劲踩刹车</p></li><li><p>尽量不开夜车，不仅不安全，而且晚上省出的时间白天还的更多</p></li></ul><h2 id="停车" tabindex="-1">停车 <a class="header-anchor" href="#停车" aria-label="Permalink to &quot;停车&quot;">​</a></h2><ul><li><p>打右转向灯提示后方</p></li><li><p>如果路面有坡，先挂 N 档，再拉手刹，再挂 P 档。</p></li><li><p>车上所有人下车都要注意后面是否来车</p></li></ul><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><ul><li><p>永远要假设别的车或人都是不规矩的</p></li><li><p>跟车不要开远光，会车更不要开远光</p></li><li><p>紧急情况下要踩死刹车才能启动 ABS，并且不要在速度没降下来的时候急打方向</p></li><li><p>车里面不要摆挂一些东西，防止急刹车砸到人身上</p></li><li><p>遇到有陌生人询问，车窗开条缝就好</p></li><li><p>车内财物不要直接放在座位上，避免别人砸窗</p></li></ul>',15)])])}const _=i(t,[["render",r]]);export{c as __pageData,_ as default};
